INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('source_title', 'My Reviews', datetime('now'));
INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('source_description', 'Honest reviews of books, films, games, and more', datetime('now'));
INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('quality_guidelines', '{"keySummary":{"tips":"Use the format: Title by Author/Creator — one-line verdict. Be opinionated, not vague."},"content":{"tips":"Structure reviews with a brief overview, what worked, what did not, and a final verdict. Use pros/cons lists for clarity."},"formatting":["Tables: comparison between similar works or specs","Bullet lists: pros/cons, standout moments, highlights","Numbered lists: ranked tracks, top episodes, best moments","Headings: separate Overview, Pros, Cons, Verdict sections","Bold: emphasize ratings or key judgments","Blockquotes: memorable quotes from the work"],"avoid":["Spoilers without warning (mark them clearly)","Vague opinions like \"it was good\" without reasoning","Pure plot summary with no personal analysis","Repeating the keySummary verdict in the content opening"]}', datetime('now'));
INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('validation_limits', '{"keySummary":{"min":10,"max":200},"content":{"min":50,"max":10000},"sourceAi":{"min":1,"max":100}}', datetime('now'));
